/// Summit deposit event signature hash.
/// keccak256("DepositEvent(bytes,bytes,bytes,bytes,bytes,bytes,bytes)")
/// Used for Summit's 7-field deposit events with Ed25519 node keys + BLS consensus keys.
pub const SUMMIT_DEPOSIT_EVENT_TOPIC: B256 =
    b256!("0x0cff1634a9a72df9d813ea7e3a3874a76086e081904ad3cf81e12e43f4d4c87a");

