/// Summit deposit event topic with Ritual's seven-field deposit event layout.
pub(crate) const SUMMIT_DEPOSIT_EVENT_TOPIC: B256 =
    b256!("0x0cff1634a9a72df9d813ea7e3a3874a76086e081904ad3cf81e12e43f4d4c87a");

/// Summit 7-field deposit event signature hash.
/// This is keccak256("DepositEvent(bytes,bytes,bytes,bytes,bytes,bytes,bytes)")
/// The Solidity contract uses "DepositEvent" as the name, not "SummitDepositEvent".
const SUMMIT_DEPOSIT_SIGNATURE: B256 =
    b256!("0cff1634a9a72df9d813ea7e3a3874a76086e081904ad3cf81e12e43f4d4c87a");
...
topic == Some(&DepositEvent::SIGNATURE_HASH) || topic == Some(&SUMMIT_DEPOSIT_SIGNATURE)
